import 'server-only';
import { ImapFlow } from 'imapflow';
import { decrypt } from './encryption';

export interface ImapCredentials {
  imapHost: string | null;
  imapPort: number | null;
  imapSecure: boolean | null;
  accountId: string;
  password: string | null;
}

function buildImapClient(creds: ImapCredentials): ImapFlow {
  return new ImapFlow({
    host: creds.imapHost ?? '',
    port: creds.imapPort ?? 993,
    secure: creds.imapSecure ?? true,
    auth: { user: creds.accountId, pass: decrypt(creds.password ?? '') },
    logger: false,
  });
}

export async function withImapClient<T>(
  creds: ImapCredentials,
  fn: (client: ImapFlow) => Promise<T>
): Promise<T> {
  const client = buildImapClient(creds);
  await client.connect();
  try {
    return await fn(client);
  } finally {
    client.close();
  }
}

import 'server-only';
import { ImapFlow } from 'imapflow';
import { decrypt } from './encryption';

export interface ImapCredentials {
  accountId: string;
  password: string | null;
}

function buildImapClient(creds: ImapCredentials): ImapFlow {
  return new ImapFlow({
    host: process.env.MAIL_HOST!,
    port: 993,
    secure: true,
    auth: { user: creds.accountId, pass: decrypt(creds.password ?? '') },
    logger: false,
  });
}

export async function withImapClient<T>(
  creds: ImapCredentials,
  fn: (client: ImapFlow) => Promise<T>
): Promise<T> {
  const client = buildImapClient(creds);
  await client.connect();
  try {
    return await fn(client);
  } finally {
    client.close();
  }
}

import 'server-only';
import nodemailer from 'nodemailer';
import { decrypt } from './encryption';

export interface SmtpCredentials {
  smtpHost: string | null;
  smtpPort: number | null;
  smtpSecure: boolean | null;
  accountId: string;
  password: string | null;
}

export function createSmtpTransport(creds: SmtpCredentials) {
  return nodemailer.createTransport({
    host: creds.smtpHost ?? '',
    port: creds.smtpPort ?? 587,
    secure: creds.smtpSecure ?? false,
    auth: { user: creds.accountId, pass: decrypt(creds.password ?? '') },
  });
}

import 'server-only';
import nodemailer from 'nodemailer';
import { decrypt } from './encryption';

export interface SmtpCredentials {
  accountId: string;
  password: string | null;
}

export function createSmtpTransport(creds: SmtpCredentials) {
  return nodemailer.createTransport({
    host: process.env.MAIL_HOST!,
    port: 587,
    secure: false,
    auth: { user: creds.accountId, pass: decrypt(creds.password ?? '') },
  });
}

